commands.cmd:
set --
[ -n '' ] && set -- "$@" --context ''
nodes=$(kubectl get nodes "$@" -o json) || { echo "kubectl get nodes failed" >&2; exit 1; }
printf '%s' "$nodes" | jq -c '{
  results: [.items[] | {
    name: .metadata.name,
    ready: (((.status.conditions // []) | map(select(.type == "Ready")) | first | .status) // "Unknown"),
    memory_pressure: (((.status.conditions // []) | map(select(.type == "MemoryPressure")) | first | .status) // "Unknown"),
    disk_pressure: (((.status.conditions // []) | map(select(.type == "DiskPressure")) | first | .status) // "Unknown"),
    pid_pressure: (((.status.conditions // []) | map(select(.type == "PIDPressure")) | first | .status) // "Unknown")
  }]
}' || { echo "jq failed" >&2; exit 1; }
